// Image data embedded at build time — used as nodemailer CID attachments only.
// Do NOT use these as <img src> — email clients block data: URIs.

const QR_B64 = ''
const APPSTORE_B64 = ''
const GOOGLEPLAY_B64 = ''

export interface EmailImageAttachment {
  filename: string
  content: Buffer
  cid: string
  contentDisposition: 'inline'
}

export function getEmailImageAttachments(): EmailImageAttachment[] {
  return [
    {
      filename: 'qr-line-openchat.jpg',
      content: Buffer.from(QR_B64, 'base64'),
      cid: 'qr-line-openchat',
      contentDisposition: 'inline',
    },
    {
      filename: 'banner-appstore.png',
      content: Buffer.from(APPSTORE_B64, 'base64'),
      cid: 'banner-appstore',
      contentDisposition: 'inline',
    },
    {
      filename: 'banner-googleplay.png',
      content: Buffer.from(GOOGLEPLAY_B64, 'base64'),
      cid: 'banner-googleplay',
      contentDisposition: 'inline',
    },
  ]
}
